class Solution {
    private static class TrieNode {
        TrieNode[] children = new TrieNode[2];
        int count = 0;
    }

    private TrieNode root;
    private int low, high;

    public int countPairs(int[] nums, int low, int high) {
        this.low = low;
        this.high = high;
        root = new TrieNode();
        int res = 0;
        for (int num : nums) {
            res += countLessEqual(num, high) - countLessEqual(num, low - 1);
            insert(num);
        }
        return res;
    }

    private void insert(int num) {
        TrieNode node = root;
        for (int i = 15; i >= 0; i--) {
            int bit = (num >> i) & 1;
            if (node.children[bit] == null) {
                node.children[bit] = new TrieNode();
            }
            node = node.children[bit];
            node.count++;
        }
    }

    private int countLessEqual(int num, int limit) {
        TrieNode node = root;
        int res = 0;
        for (int i = 15; i >= 0; i--) {
            if (node == null) break;
            int bitNum = (num >> i) & 1;
            int bitLimit = (limit >> i) & 1;
            if (bitLimit == 1) {
                if (node.children[bitNum] != null) {
                    res += node.children[bitNum].count;
                }
                node = node.children[1 - bitNum];
            } else {
                node = node.children[bitNum];
            }
        }
        return res;
    }
}
